/** Encode a NodeDirective union as a tagged sum [variant_index, value]. */
fun NodeDirective.toCborValue(): CborValue = when (this) {
    is NodeDirectiveVariant0 -> CborValue.CArray(listOf(CborValue.CUint(0uL), this.value.toCborValue()))
    is NodeDirectiveVariant1 -> CborValue.CArray(listOf(CborValue.CUint(1uL), this.value.toCborValue()))
    is NodeDirectiveVariant2 -> CborValue.CArray(listOf(CborValue.CUint(2uL), this.value.toCborValue()))
    is NodeDirectiveVariant3 -> CborValue.CArray(listOf(CborValue.CUint(3uL), this.value.toCborValue()))
    is NodeDirectiveVariant4 -> CborValue.CArray(listOf(CborValue.CUint(4uL), this.value.toCborValue()))
}

/** Decode a tagged sum [variant_index, value] into a NodeDirective union. */
fun nodeDirectiveFromCborValue(cbor: CborValue): NodeDirective {
    val csilArr = CsilCbor.asArray(cbor)
    if (csilArr.size != 2) throw CborError("union expects [index, value]")
    return when (CsilCbor.asULong(csilArr[0])) {
        0uL -> NodeDirectiveVariant0(dirLoadFromCborValue(csilArr[1]))
        1uL -> NodeDirectiveVariant1(dirPauseFromCborValue(csilArr[1]))
        2uL -> NodeDirectiveVariant2(dirResumeFromCborValue(csilArr[1]))
        3uL -> NodeDirectiveVariant3(dirStopFromCborValue(csilArr[1]))
        4uL -> NodeDirectiveVariant4(dirVolumeFromCborValue(csilArr[1]))
        else -> throw CborError("unknown NodeDirective variant")
    }
}

